// src/components/TTSButton.js
import React from 'react';
import { PlayIcon, PauseIcon } from '@heroicons/react/24/solid';
import useSpeechSynthesis from './speech-synthesis';

const TTSButton = ({ text }) => {
  const { isPlaying, toggleSpeech } = useSpeechSynthesis(text, {
    rate: 0.9, // Adjust the rate to slow down the voice
    pitch: 1, // Adjust the pitch if needed
    volume: 1, // Adjust the volume if needed
  });

  return (
    <div className="text-to-speech">
      <button
        onClick={toggleSpeech}
      >
        {isPlaying ? (
          <>
            <PauseIcon className="h-6 w-6 text-gray-700 mr-2" />
            Pause
          </>
        ) : (
          <>
            <PlayIcon className="h-6 w-6 text-gray-700 mr-2" />
            Play
          </>
        )}
      </button>
    </div>
  );
};

export default TTSButton;
